        // Phone number validation
        function validatePhone(phone) {
            return /^[0-9]{10}$/.test(phone.replace(/\D/g, ''));
        }

        // Email validation
        function validateEmail(email) {
            return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
        }

        // Send receipt via email
        async function sendReceipt(email, phone, order) {
            try {
                const response = await fetch('/api/send-receipt', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ email, phone, order })
                });
                if (response.ok) {
                    showNotification(`📧 Receipt sent to ${email}!`);
                } else {
                    console.log('Receipt sending failed, but order saved');
                }
            } catch (error) {
                console.log('Email service unavailable, order saved to localStorage');
            }
        }

