        // Display allocated table banner
        // Small date helper (dd/mm/yyyy, HH:MM:SS)
        function formatDateTime(value, includeTime = true) {
            if (!value && value !== 0) return '-';
            const d = new Date(value);
            if (isNaN(d.getTime())) return String(value);
            const dd = String(d.getDate()).padStart(2, '0');
            const mm = String(d.getMonth() + 1).padStart(2, '0');
            const yyyy = d.getFullYear();
            if (!includeTime) return `${dd}/${mm}/${yyyy}`;
            const hh = String(d.getHours()).padStart(2, '0');
            const min = String(d.getMinutes()).padStart(2, '0');
            const ss = String(d.getSeconds()).padStart(2, '0');
            return `${dd}/${mm}/${yyyy}, ${hh}:${min}:${ss}`;
        }

        function displayAllocatedTable() {
            const allocatedTable = sessionStorage.getItem('allocatedTableNumber');
            const allocatedAt = sessionStorage.getItem('allocatedAt');
            const assignedAt = sessionStorage.getItem('tableAssignedAt');
            const tableAllocatedBanner = document.getElementById('tableAllocatedBanner');
            const displayTableNum = document.getElementById('displayTableNum');
            const displayAllocatedTime = document.getElementById('displayAllocatedTime');
            const displayAssignedTime = document.getElementById('displayAssignedTime');
            
            if (allocatedTable) {
                displayTableNum.textContent = allocatedTable;
                if (displayAllocatedTime && allocatedAt) {
                    try {
                        displayAllocatedTime.textContent = formatDateTime(parseInt(allocatedAt));
                    } catch (e) {
                        displayAllocatedTime.textContent = allocatedAt;
                    }
                }
                if (displayAssignedTime && assignedAt) {
                    try {
                        displayAssignedTime.textContent = formatDateTime(parseInt(assignedAt));
                    } catch (e) {
                        displayAssignedTime.textContent = assignedAt;
                    }
                }
                tableAllocatedBanner.classList.remove('hidden');
            }
        }
        
