        // Update notification count in navbar
        function updateNotificationCount() {
            const unreadCount = notifications.filter(n => !n.read).length;
            
            if (unreadCount > 0) {
                notificationCount.textContent = unreadCount;
                notificationCount.classList.remove('hidden');
            } else {
                notificationCount.classList.add('hidden');
            }
        }

        // Load order history
        function loadOrderHistory() {
            if (orders.length === 0) {
                orderHistoryItems.innerHTML = '<p class="text-gray-500">You haven\'t placed any orders yet.</p>';
                return;
            }
            
            orderHistoryItems.innerHTML = '';
            
            orders.forEach((order, index) => {
                const orderItem = document.createElement('div');
                orderItem.className = 'bg-white rounded-lg shadow-sm p-4';
                orderItem.innerHTML = `
                    <div class="flex justify-between items-center mb-2">
                        <h3 class="font-bold text-gray-800">Order #${orders.length - index}</h3>
                        <span class="text-gray-600 text-sm">${new Date(order.date).toLocaleDateString()}</span>
                    </div>
                    <div class="text-green-600 font-medium mb-2">₹${order.total.toFixed(2)}</div>
                    <div class="text-gray-600 text-sm">${order.items.length} items</div>
                `;
                orderHistoryItems.appendChild(orderItem);
            });
        }

        // Generate QR code for payment
        function generateQRCode(amount) {
            const paymentData = {
                merchant: 'Love-Bite Restaurant',
                amount: amount,
                currency: 'INR',
                timestamp: new Date().toISOString(),
                orderId: `LB-${Date.now()}`
            };
            
            QRCode.toCanvas(qrCodeEl, JSON.stringify(paymentData), { width: 200 }, error => {
                if (error) console.error('QR code generation error:', error);
            });
        }

        // Complete order
        async function completeOrder() {
            const phoneNumber = phoneNumberInput.value.trim();
            const email = (emailAddressInput && emailAddressInput.value.trim()) || '';
            const tableNumber = tableNumberInput.value.trim();
            const orderTotal = parseFloat(totalAmountEl.textContent.substring(1));

            // Validate formats if provided (phone/email are optional)
            if (phoneNumber && !validatePhone(phoneNumber)) {
                phoneErrorMsg.classList.remove('hidden');
                showNotification('❌ Phone format looks invalid — order will still be placed');
            } else {
                phoneErrorMsg.classList.add('hidden');
            }

            const emailErrorMsg = document.getElementById('emailError');
            if (email && !validateEmail(email)) {
                if (emailErrorMsg) emailErrorMsg.classList.remove('hidden');
                showNotification('❌ Email format looks invalid — order will still be placed');
            } else {
                if (emailErrorMsg) emailErrorMsg.classList.add('hidden');
            }

            const newOrder = {
                id: Date.now(),
                items: [...cart],
                total: orderTotal,
                date: new Date(),
                phoneNumber: phoneNumber || '',
                email: email || '',
                tableNumber: tableNumber || 'Not provided'
            };
            
            // Show notifications
            showNotification(`✅ Order confirmed!`);
            
            if (tableNumber) {
                showNotification(`🪑 Table ${tableNumber} reserved for your order`);
            }
            
                        // POST order to server and reconcile server-assigned id (if any)
            try {
                const resp = await fetch('/api/orders', {
                  method: 'POST',
                  headers: {'Content-Type': 'application/json'},
                  body: JSON.stringify(newOrder)
                });
                const data = resp.ok ? await resp.json() : null;
                // If server returned a different id, update our local copy
                if (data && data.orderId && data.orderId !== newOrder.id) {
                    newOrder.id = data.orderId;
                }
            } catch (e) {
                // server unavailable — we will rely on localStorage fallback
            }

            // Store locally so manager dashboard can read from localStorage when server is not available
            orders.unshift(newOrder);
            localStorage.setItem('orders', JSON.stringify(orders));
            // Dispatch a custom event so same-tab manager UI can react immediately
            try { window.dispatchEvent(new CustomEvent('orders-updated', { detail: newOrder })); } catch(e) { /* ignore */ }
            
            // Clear cart completely
            
            cart = [];
            localStorage.setItem('cart', JSON.stringify(cart));
            
            // Update UI
            updateCart();
            updateCartCount();
            closePaymentModal();
            closeCartSidebar();
            loadOrderHistory();
            
            // Reset inputs
            phoneNumberInput.value = '';
            if (emailAddressInput) emailAddressInput.value = '';
            tableNumberInput.value = '';

            // Attempt to send receipt (email + SMS via server) — only if contact provided
            if (email || phoneNumber) {
                try {
                    sendReceipt(email, phoneNumber, newOrder);
                } catch (e) {
                    console.warn('sendReceipt failed', e);
                }
            }
            
            // Show success message
            setTimeout(() => {
                alert('🎉 Payment successful! Your order has been placed.\n\nOrder ID: ' + newOrder.id);
            }, 500);
        }

        // Toggle cart sidebar
        function toggleCartSidebar() {
            if (cartSidebar.classList.contains('translate-x-full')) {
                cartSidebar.classList.remove('translate-x-full');
                overlay.classList.remove('hidden');
                document.body.style.overflow = 'hidden';
            } else {
                closeCartSidebar();
            }
        }

        // Close cart sidebar
        function closeCartSidebar() {
            cartSidebar.classList.add('translate-x-full');
            overlay.classList.add('hidden');
            document.body.style.overflow = '';
        }

        // Open payment modal
        function openPaymentModal() {
            if (cart.length === 0) return;
            
            paymentModal.classList.remove('hidden');
            overlay.classList.remove('hidden');
            generateQRCode(parseFloat(totalAmountEl.textContent.substring(1)));
        }

        // Close payment modal
        function closePaymentModal() {
            paymentModal.classList.add('hidden');
            overlay.classList.add('hidden');
        }

        // Toggle notification panel
        function toggleNotificationPanel() {
            if (notificationPanel.classList.contains('hidden')) {
                notificationPanel.classList.remove('hidden');
                
                // Mark notifications as read
                notifications = notifications.map(n => ({ ...n, read: true }));
                localStorage.setItem('notifications', JSON.stringify(notifications));
                updateNotificationCount();
            } else {
                notificationPanel.classList.add('hidden');
            }
        }

        // Filter menu items by search term
        function filterMenuItems(searchTerm) {
            const filteredItems = menuItems.filter(item => 
                item.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                item.description.toLowerCase().includes(searchTerm.toLowerCase()) ||
                item.category.toLowerCase().includes(searchTerm.toLowerCase())
            );
            
            renderMenuItems(filteredItems);
        }

        // Filter menu items by category
        function filterByCategory(category) {
            if (category === 'All Items') {
                renderMenuItems(menuItems);
            } else {
                const filteredItems = menuItems.filter(item => item.category === category);
                renderMenuItems(filteredItems);
            }
        }

        // Switch between sections
        function switchSection(section) {
            menuSection.classList.add('hidden');
            orderHistorySection.classList.add('hidden');
            aboutSection.classList.add('hidden');
            
            document.querySelectorAll('.nav-item').forEach(navItem => {
                navItem.classList.remove('active-nav');
                navItem.classList.add('text-gray-500');
            });
            
            section.classList.remove('hidden');
            
            // Update active nav
            if (section === menuSection) {
                homeNav.classList.add('active-nav');
                homeNav.classList.remove('text-gray-500');
                homeNav.classList.add('text-gray-800');
            } else if (section === orderHistorySection) {
                orderHistoryNav.classList.add('active-nav');
                orderHistoryNav.classList.remove('text-gray-500');
                orderHistoryNav.classList.add('text-gray-800');
            } else if (section === aboutSection) {
                aboutNav.classList.add('active-nav');
                aboutNav.classList.remove('text-gray-500');
                aboutNav.classList.add('text-gray-800');
            }
        }

        // Event Listeners
        cartBtn.addEventListener('click', toggleCartSidebar);
        closeCartBtn.addEventListener('click', closeCartSidebar);
        overlay.addEventListener('click', () => {
            closeCartSidebar();
            closePaymentModal();
        });
        
        checkoutBtn.addEventListener('click', openPaymentModal);
        closePaymentModalBtn.addEventListener('click', closePaymentModal);
        confirmPaymentBtn.addEventListener('click', completeOrder);
        
        const clearCartBtn = document.getElementById('clearCartBtn');
        clearCartBtn.addEventListener('click', clearCart);
        
        phoneNumberInput.addEventListener('input', function() {
            // phone/email optional for checkout; only require non-empty cart
            checkoutBtn.disabled = cart.length === 0;
            // Show/hide phone validation error (non-blocking)
            if (this.value.trim() && !validatePhone(this.value)) {
                phoneErrorMsg.classList.remove('hidden');
            } else {
                phoneErrorMsg.classList.add('hidden');
            }
        });

        if (emailAddressInput) {
            const emailErrorMsg = document.getElementById('emailError');
            emailAddressInput.addEventListener('input', function() {
                // phone/email optional for checkout; only require non-empty cart
                checkoutBtn.disabled = cart.length === 0;

                if (this.value.trim() && !validateEmail(this.value)) {
                    if (emailErrorMsg) emailErrorMsg.classList.remove('hidden');
                } else {
                    if (emailErrorMsg) emailErrorMsg.classList.add('hidden');
                }
            });
        }

        
        // Book table link in payment modal
        bookTableLink.addEventListener('click', function(e) {
            e.preventDefault();
            closePaymentModal();
            // Trigger the booking button click
            document.getElementById('bookingBtn').click();
            showNotification('📅 Redirecting to table booking...');
        });
        
        notificationBtn.addEventListener('click', toggleNotificationPanel);
        
        searchInput.addEventListener('input', function() {
            filterMenuItems(this.value);
        });
        
        categoryButtons.forEach(button => {
            button.addEventListener('click', function() {
                categoryButtons.forEach(btn => {
                    btn.classList.remove('bg-pink-600', 'text-white');
                    btn.classList.add('bg-gray-200', 'text-gray-700');
                });
                
                this.classList.remove('bg-gray-200', 'text-gray-700');
                this.classList.add('bg-pink-600', 'text-white');
                
                filterByCategory(this.textContent);
            });
        });
        
        homeNav.addEventListener('click', () => switchSection(menuSection));
        orderHistoryNav.addEventListener('click', () => switchSection(orderHistorySection));
        aboutNav.addEventListener('click', () => switchSection(aboutSection));

        // Initialize the app
        document.addEventListener('DOMContentLoaded', initApp);

    
